const raw = items[0].json;
let content;

try {
  if (typeof raw === 'object' && raw.slides) {
    content = raw;
  } else if (raw.content && raw.content.parts && Array.isArray(raw.content.parts)) {
    let jsonText = '';
    for (const part of raw.content.parts) {
      if (part.thought) continue;
      if (part.text) jsonText = part.text;
    }
    jsonText = jsonText.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
    content = JSON.parse(jsonText);
  } else if (typeof raw === 'string') {
    const cleaned = raw.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
    content = JSON.parse(cleaned);
  } else if (typeof raw.content === 'string') {
    const cleaned = raw.content.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
    content = JSON.parse(cleaned);
  } else if (raw.text && typeof raw.text === 'string') {
    const cleaned = raw.text.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
    content = JSON.parse(cleaned);
  } else {
    const str = JSON.stringify(raw);
    const slidesMatch = str.match(/"slides"\s*:\s*\[/);
    if (slidesMatch) {
      let startIdx = str.indexOf(slidesMatch[0]);
      for (let i = startIdx; i >= 0; i--) {
        if (str[i] === '{') { startIdx = i; break; }
      }
      let depth = 0, endIdx = startIdx;
      for (let i = startIdx; i < str.length; i++) {
        if (str[i] === '{') depth++;
        if (str[i] === '}') { depth--; if (depth === 0) { endIdx = i + 1; break; } }
      }
      content = JSON.parse(str.substring(startIdx, endIdx));
    } else {
      throw new Error('No slides data found in input');
    }
  }
} catch (e) {
  throw new Error('Failed to parse carousel content: ' + e.message + '. Raw keys: ' + Object.keys(raw));
}

if (!content || !content.slides || content.slides.length === 0) {
  throw new Error('No slides found. Parsed content keys: ' + (content ? Object.keys(content) : 'null'));
}

const avatar = 'a small 8-bit pixel art avatar character with neutral styling, dark hair, expressive eyes, slight confident smirk, wearing a dark hoodie with a simple emblem, anime pixel-art style';

const brandBase = 'Create a perfectly square 1080x1080 pixel Instagram carousel slide. ABSOLUTE RULES: Pure solid black (#000000) background filling the entire canvas. ALL text rendered in clean white (#FFFFFF) sans-serif font. Accent colors ONLY for thin decorative elements: cyber-purple (#7B2FBE) and electric blue (#00D4FF). Design must be ultra-clean, modern, minimal. NO photographs, NO 3D renders, NO gradients on background. Only flat graphic design, clean typography, and subtle geometric accents (thin neon lines, small dots, angular corner decorations). ';

const slides = content.slides;
const output = [];

for (const slide of slides) {
  let prompt = brandBase;

  if (slide.type === 'cover') {
    prompt += 'Include ' + avatar + ' positioned in the bottom-right area, sized about 25% of the slide, looking excited and pointing upward. ';
    prompt += 'LAYOUT: Large bold white headline text ' + (slide.headline || '') + ' centered in the upper 60% of the slide. ';
    prompt += 'Smaller text below in electric blue: ' + (slide.subtext || '') + '. ';
    prompt += 'A thin glowing purple (#7B2FBE) accent line under the headline. Very thin purple border around entire slide. ';
    prompt += 'Tiny @[HANDLE] watermark at bottom-left in dark gray. Subtle dot grid pattern barely visible in corners.';
  } else if (slide.type === 'cta') {
    prompt += 'Include ' + avatar + ' centered in the middle of the slide, larger (about 35% of slide), waving with a friendly expression. ';
    prompt += 'LAYOUT: Bold text ' + (slide.headline || '') + ' at the top in white. ';
    prompt += 'Below the avatar: ' + (slide.subtext || '') + ' in electric blue (#00D4FF). ';
    prompt += 'A subtle right-pointing arrow icon (swipe indicator). Glowing thin purple border. Subtle futuristic grid pattern in background.';
  } else {
    prompt += 'Include ' + avatar + ' very small (about 10% of slide) in the top-right corner. ';
    prompt += 'LAYOUT: Label text ' + (slide.label || 'DID YOU KNOW?') + ' at the top in electric blue (#00D4FF), smaller font. ';
    prompt += 'A thin purple horizontal line separator below the label. ';
    prompt += 'Main body text: ' + (slide.body || '') + ' in large bold white text, centered vertically in the middle 60% of the slide. ';
    prompt += 'Slide number ' + (slide.num || '') + '/6 very small at the bottom-center in dark gray. Subtle angular decorations in bottom corners.';
  }

  output.push({
    json: {
      slideNum: slide.num,
      slideType: slide.type,
      imagePrompt: prompt,
      caption: content.caption || '',
      topic: content.topic || ''
    }
  });
}

return output;

const slideNum = $json.slideNum || ($itemIndex + 1);
const caption = $json.caption || '';
const topic = $json.topic || '';

const comment = slideNum === 1
  ? '\u{1F4F1} *NEW CAROUSEL READY* \u2014 ' + topic + '\n\n' + caption + '\n\n_Slide ' + slideNum + '/6_'
  : '_Slide ' + slideNum + '/6_';

return {
  json: {
    ...$json,
    slackComment: comment,
    fileName: 'carousel_slide_' + String(slideNum).padStart(2, '0') + '.png'
  },
  binary: $binary
};

// Map the input items into a single string
// Note: "Topic" must match your Google Sheet column name exactly!
const history = items.map(i => i.json.Topic).filter(t => t).join(', ');

return { 
  history: history || "None yet" 
};
